/* ============================================================
   BEK TOUR — Main JS v3 (full i18n + all fixes)
   ============================================================ */
'use strict';

function getCookie(n) { return document.cookie.split(';').reduce((a,c)=>{const[k,v]=c.trim().split('=');return k===n?decodeURIComponent(v):a;},null); }
function setCookie(n,v,d=365) { document.cookie=`${n}=${encodeURIComponent(v)};path=/;max-age=${d*86400}`; }
function qs(s,c=document)  { return c.querySelector(s); }
function qsa(s,c=document) { return [...c.querySelectorAll(s)]; }

const LANG = getCookie('bt_lang') || 'ru';

// ── Lang switcher ────────────────────────────────────────────
window.setLang = function(l) { setCookie('bt_lang',l); location.reload(); };

function t(key) {
  const translations = window.I18N;
  if (!translations) return key;
  return (translations[LANG] || translations.ru)[key] || (translations.ru)[key] || key;
}

// Apply all i18n keys to DOM after components loaded
function applyI18n() {
  // Lang buttons active state
  qsa('.nav-lang a').forEach(a => {
    const l = a.textContent.trim().toLowerCase();
    a.classList.toggle('on', l === LANG);
  });

  // All elements with data-i18n attribute
  qsa('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    const val = t(key);
    if (val && val !== key) {
      if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') el.placeholder = val;
      else el.textContent = val;
    }
  });

  // Placeholders
  qsa('[data-i18n-ph]').forEach(el => {
    const val = t(el.dataset.i18nPh);
    if (val) el.placeholder = val;
  });
}

// ── Loader ───────────────────────────────────────────────────
(function(){
  const L=document.getElementById('bt-loader');
  if(!L) return;
  if(sessionStorage.getItem('bt_seen')){L.remove();return;}
  const logo=L.querySelector('.loader-logo'),sub=L.querySelector('.loader-sub'),
        bar=L.querySelector('.loader-bar-fill'),pct=L.querySelector('.loader-pct'),
        status=L.querySelector('.loader-status'),curtain=L.querySelector('.loader-curtain');
  const statuses={ru:['Открываем карту...','Шёлковый путь ждёт...','Готовим маршруты...','Почти готово'],
                  en:['Opening the map...','The Silk Road awaits...','Preparing routes...','Almost ready'],
                  uz:['Xaritani ochamiz...','Ipak yo\'li kutmoqda...','Marshrutlar tayyor...','Deyarli tayyor']};
  const st = statuses[LANG] || statuses.ru;
  document.documentElement.style.overflow='hidden';
  setTimeout(()=>{if(!logo)return;logo.style.transition='clip-path 1.1s cubic-bezier(.76,0,.24,1),opacity .5s';logo.style.clipPath='inset(0 0 0 0)';logo.style.opacity='1';},150);
  setTimeout(()=>{if(!sub)return;sub.style.transition='opacity .8s,transform .8s cubic-bezier(.22,1,.36,1)';sub.style.opacity='1';sub.style.transform='none';},700);
  const t0=performance.now(),DUR=2200;let done=false;
  function reveal(){
    if(done)return;done=true;
    sessionStorage.setItem('bt_seen','1');
    document.documentElement.style.overflow='';
    if(curtain)Array.from(curtain.children).forEach((s,i)=>{s.style.transition=`transform .75s cubic-bezier(.76,0,.24,1) ${i*.07}s`;s.style.transform='translateY(-101%)';});
    setTimeout(()=>{L.style.transition='opacity .3s';L.style.opacity='0';},300);
    setTimeout(()=>L.remove(),1150);
  }
  function tick(now){
    const p=Math.min((now-t0)/DUR,1),e=1-Math.pow(1-p,3),v=Math.round(e*100);
    if(bar)bar.style.width=v+'%';
    if(pct)pct.textContent=v;
    if(status)status.textContent=st[Math.min(3,Math.floor(e*4))];
    if(p<1)requestAnimationFrame(tick);else setTimeout(reveal,260);
  }
  requestAnimationFrame(tick);
  setTimeout(reveal,DUR+1500);
  window.addEventListener('load',reveal,{once:true});
})();

// ── Scroll progress ───────────────────────────────────────────
(function(){
  const bar=qs('.scroll-progress');if(!bar)return;
  window.addEventListener('scroll',()=>{const h=document.documentElement.scrollHeight-window.innerHeight;bar.style.width=(h>0?window.scrollY/h*100:0)+'%';},{passive:true});
})();

// ── Navbar scroll ─────────────────────────────────────────────
(function(){
  const nav=qs('.navbar');if(!nav)return;
  const sync=()=>nav.classList.toggle('scrolled',window.scrollY>50);
  window.addEventListener('scroll',sync,{passive:true});sync();
})();

// ── Active nav/tab ────────────────────────────────────────────
function syncActiveNav(){
  const fn=location.pathname.split('/').pop()||'index.html';
  qsa('.nav-link[href]').forEach(a=>a.classList.toggle('active',a.getAttribute('href').split('?')[0]===fn));
  qsa('.tab[href]').forEach(t=>t.classList.toggle('active',t.getAttribute('href').split('?')[0]===fn));
}

// ── Mobile nav ────────────────────────────────────────────────
function initMobileNav(){
  const burger=qs('.nav-burger'),mNav=qs('.mobile-nav'),overlay=qs('.menu-overlay'),closeBtn=qs('.mobile-nav-close');
  if(!burger||!mNav)return;
  const open_=()=>{mNav.classList.add('open');overlay?.classList.add('open');document.body.style.overflow='hidden';};
  const close_=()=>{mNav.classList.remove('open');overlay?.classList.remove('open');document.body.style.overflow='';};
  burger.addEventListener('click',open_);
  closeBtn?.addEventListener('click',close_);
  overlay?.addEventListener('click',close_);
}

// ── Hero Slider ───────────────────────────────────────────────
(function(){
  const slides=qsa('.hero-slide');if(!slides.length)return;
  let cur=0,timer;
  const dotsWrap=qs('#slider-dots');
  if(dotsWrap)dotsWrap.innerHTML=slides.map((_,i)=>`<div class="slider-dot${i===0?' active':''}" onclick="heroGoTo(${i})"></div>`).join('');
  function goTo(n){
    slides[cur].classList.remove('active');
    cur=(n+slides.length)%slides.length;
    slides[cur].classList.add('active');
    qsa('.slider-dot').forEach((d,i)=>d.classList.toggle('active',i===cur));
    clearInterval(timer);timer=setInterval(()=>goTo(cur+1),5500);
  }
  window.heroGoTo=goTo;
  qs('.slider-prev')?.addEventListener('click',()=>goTo(cur-1));
  qs('.slider-next')?.addEventListener('click',()=>goTo(cur+1));
  let tx=0;
  qs('.hero-slider')?.addEventListener('touchstart',e=>{tx=e.touches[0].clientX;},{passive:true});
  qs('.hero-slider')?.addEventListener('touchend',e=>{const dx=e.changedTouches[0].clientX-tx;if(Math.abs(dx)>40)goTo(cur+(dx<0?1:-1));});
  timer=setInterval(()=>goTo(cur+1),5500);
})();

// ── FAQ ───────────────────────────────────────────────────────
function initFAQ(){
  qsa('.faq-q').forEach(q=>{
    q.addEventListener('click',()=>{
      const item=q.closest('.faq-item'),ans=item.querySelector('.faq-a'),open=item.classList.contains('open');
      qsa('.faq-item.open').forEach(i=>{i.classList.remove('open');i.querySelector('.faq-a').style.maxHeight='0';});
      if(!open){item.classList.add('open');ans.style.maxHeight=ans.scrollHeight+'px';}
    });
  });
}

// ── Reveal ────────────────────────────────────────────────────
(function(){
  const els=qsa('.reveal');if(!els.length)return;
  const obs=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('in');obs.unobserve(e.target);}});},{threshold:0.08});
  els.forEach(el=>obs.observe(el));
})();

// ── Favourites ────────────────────────────────────────────────
const favs=JSON.parse(localStorage.getItem('bt_favs')||'[]');
window.toggleFav=function(id,btn){
  const i=favs.indexOf(id);
  if(i===-1){favs.push(id);btn?.classList.add('active');showToast('❤️ '+t('fav_added'));}
  else{favs.splice(i,1);btn?.classList.remove('active');showToast(t('fav_removed'));}
  localStorage.setItem('bt_favs',JSON.stringify(favs));
};
qsa('[data-fav-id]').forEach(btn=>{
  if(favs.includes(btn.dataset.favId))btn.classList.add('active');
  btn.addEventListener('click',e=>{e.preventDefault();toggleFav(btn.dataset.favId,btn);});
});

// ── Toast ─────────────────────────────────────────────────────
window.showToast=function(msg,type=''){
  let wrap=qs('.toast-wrap');
  if(!wrap){wrap=document.createElement('div');wrap.className='toast-wrap';document.body.appendChild(wrap);}
  const el=document.createElement('div');
  el.className='toast'+(type?' '+type:'');el.textContent=msg;
  wrap.appendChild(el);
  requestAnimationFrame(()=>requestAnimationFrame(()=>el.classList.add('show')));
  setTimeout(()=>{el.classList.remove('show');setTimeout(()=>el.remove(),400);},3200);
};

// ── Calculator ────────────────────────────────────────────────
(function(){
  const totalEl=document.getElementById('calcTotal');if(!totalEl)return;
  const TOUR={silk:130,city:85,nature:95,luxury:300};
  const HOTEL={'3':0,'4':45,'5':110};
  const GUEST={'1':1,'2':1.75,'4':3.1,'6':4.4};
  const SVC={transfer:40,guide:85,visa:50,meals:48,photo:95,car:55};
  const CUR={usd:1,eur:0.92,rub:89,uzs:12500};
  const SYM={usd:'$',eur:'€',rub:'₽',uzs:'сум'};
  function calc(){
    const tour=qs('[data-key="tour"]')?.value||'silk';
    const days=parseInt(qs('[data-key="days"]')?.value||'5');
    const guests=qs('[data-key="guests"]')?.value||'2';
    const hotel=qs('[data-key="hotel"]')?.value||'4';
    const cur=qs('[data-key="currency"]')?.value||'usd';
    let base=(TOUR[tour]+(HOTEL[hotel]||0))*days*(GUEST[guests]||1);
    qsa('.calc-svc.on').forEach(s=>{base+=(SVC[s.dataset.svc]||0)*days;});
    totalEl.textContent=(SYM[cur]||'$')+Math.round(base*(CUR[cur]||1)).toLocaleString('ru-RU');
  }
  qsa('.calc-svc').forEach(s=>s.addEventListener('click',()=>{s.classList.toggle('on');calc();}));
  qsa('.calc-select').forEach(s=>s.addEventListener('change',calc));
  calc();
})();

// ── Lightbox ──────────────────────────────────────────────────
window.openLightbox=function(src,alt){
  const ov=document.createElement('div');
  ov.style.cssText='position:fixed;inset:0;background:rgba(6,24,38,.94);z-index:9999;display:flex;align-items:center;justify-content:center;padding:1rem;cursor:zoom-out;backdrop-filter:blur(10px)';
  const img=document.createElement('img');img.src=src;img.alt=alt||'';
  img.style.cssText='max-width:92vw;max-height:90vh;object-fit:contain;border-radius:14px;box-shadow:0 28px 80px rgba(0,0,0,.6)';
  ov.appendChild(img);ov.addEventListener('click',()=>ov.remove());
  document.addEventListener('keydown',e=>{if(e.key==='Escape')ov.remove();},{once:true});
  document.body.appendChild(ov);
};

// ── Catalog filter ────────────────────────────────────────────
qsa('.chip[data-cat]').forEach(c=>{
  c.addEventListener('click',()=>{
    qsa('.chip[data-cat]').forEach(x=>x.classList.remove('on'));c.classList.add('on');
    const cat=c.dataset.cat;
    qsa('[data-card]').forEach(card=>{
      const show=!cat||card.dataset.cat?.includes(cat);
      card.style.display=show?'':'none';
    });
  });
});

// ── B2B sidebar ───────────────────────────────────────────────
(function(){
  const toggle=qs('[data-b2b-toggle]'),sidebar=qs('.b2b-sidebar');
  if(!toggle||!sidebar)return;
  toggle.addEventListener('click',()=>sidebar.classList.toggle('open'));
  document.addEventListener('click',e=>{if(!sidebar.contains(e.target)&&!toggle.contains(e.target))sidebar.classList.remove('open');});
})();

// ── B2B data manager ──────────────────────────────────────────
window.BT=(function(){
  const gP=()=>JSON.parse(localStorage.getItem('bt_props')||'[]');
  const sP=a=>localStorage.setItem('bt_props',JSON.stringify(a));
  const gB=()=>JSON.parse(localStorage.getItem('bt_bookings')||'[]');
  const gU=()=>JSON.parse(localStorage.getItem('bt_user')||'{}');
  const sU=u=>localStorage.setItem('bt_user',JSON.stringify(u));
  const add=data=>{const p=gP(),id=Date.now().toString();p.unshift({id,...data,active:false,views:0,bookings:0,created:new Date().toISOString()});sP(p);return id;};
  const upd=(id,data)=>{const p=gP(),i=p.findIndex(x=>x.id===id);if(i!==-1){p[i]={...p[i],...data};sP(p);}};
  const del=id=>sP(gP().filter(p=>p.id!==id));
  const tog=id=>{const p=gP(),x=p.find(i=>i.id===id);if(x){x.active=!x.active;sP(p);return x.active;}return false;};
  return{getProps:gP,saveProps:sP,getBookings:gB,getUser:gU,saveUser:sU,addProp:add,updateProp:upd,deleteProp:del,toggleActive:tog};
})();

// ── Search ────────────────────────────────────────────────────
(function(){
  const btn=qs('#searchToggle'),bar=qs('#searchBar'),input=qs('#searchInput');
  if(!btn||!bar)return;
  btn.addEventListener('click',()=>{bar.classList.toggle('hidden');if(!bar.classList.contains('hidden'))input?.focus();});
  input?.addEventListener('keydown',e=>{
    if(e.key==='Enter'&&input.value.trim())location.href=`destinations.html?q=${encodeURIComponent(input.value.trim())}`;
    if(e.key==='Escape')bar.classList.add('hidden');
  });
})();

// ── Newsletter ────────────────────────────────────────────────
window.nlSubmit=function(){
  const v=qs('#nlEmail')?.value;
  if(!v||!v.includes('@')){showToast(t('nl_err')||'Введите корректный email','error');return;}
  showToast('✅ '+( t('nl_ok')||'Спасибо! Вы подписаны'),'success');
  if(qs('#nlEmail'))qs('#nlEmail').value='';
};

// ── onComponentsLoaded — вызывается после fetch компонентов ──
window.onComponentsLoaded=function(){
  applyI18n();
  syncActiveNav();
  initMobileNav();
  initFAQ();
  // Fix hero margin after navbar renders
  const nav=qs('.navbar'),hero=qs('.hero-slider,.dest-hero,.page-hero');
  if(nav&&hero)hero.style.marginTop=`-${nav.offsetHeight}px`;
  // Search input placeholder
  const si=qs('#searchInput');if(si)si.placeholder=t('nav_search_ph');
};

// ── Init ──────────────────────────────────────────────────────
document.addEventListener('DOMContentLoaded',()=>{
  syncActiveNav();
  initFAQ();
  if(window.I18N) applyI18n();
});

window.bookWhatsApp=function(name,price){
  window.open(`https://wa.me/998901234567?text=${encodeURIComponent(`Здравствуйте! Хочу забронировать "${name}". Стоимость: ${price}`)}`, '_blank');
};

